package com.bank.ea.config;
import org.springframework.context.annotation.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.core.userdetails.*; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.provisioning.InMemoryUserDetailsManager; import org.springframework.security.web.SecurityFilterChain;
@Configuration public class SecurityConfig { @Bean PasswordEncoder encoder(){return new BCryptPasswordEncoder();} @Bean UserDetailsService users(PasswordEncoder e){String password=System.getenv("EA_ADMIN_PASSWORD");if(password==null||password.isBlank())throw new IllegalStateException("EA_ADMIN_PASSWORD must be set");UserDetails admin=User.withUsername(System.getenv().getOrDefault("EA_ADMIN_USER","admin")).password(e.encode(password)).roles("ADMIN","ARCHITECT","AUDITOR").build();return new InMemoryUserDetailsManager(admin);}@Bean SecurityFilterChain security(HttpSecurity h)throws Exception{return h.authorizeHttpRequests(a->a.requestMatchers("/css/**","/actuator/health").permitAll().anyRequest().authenticated()).formLogin(f->f.loginPage("/login").permitAll().defaultSuccessUrl("/",true)).logout(l->l.logoutSuccessUrl("/login?logout")).build();}}
